import React, { useState, useEffect, useRef } from 'react';
import './App.css';

function App() {
  const [step, setStep] = useState('profile'); // profile, chat
  const [gpa, setGpa] = useState('');
  const [interests, setInterests] = useState('');
  const [messages, setMessages] = useState([]);
  const [inputMessage, setInputMessage] = useState('');
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef(null);

  // Scroll to bottom of chat
  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const submitProfile = async () => {
    if (!gpa || !interests) {
      alert('Please fill both fields!');
      return;
    }

    setLoading(true);
    try {
      const response = await fetch('http://localhost:5000/api/register', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          username: 'Lahar',
          email: 'lahar@test.com',
          password: 'pass123',
          gpa: parseFloat(gpa),
          interests: interests
        })
      });

      await response.json();
      
      // Switch to chat + welcome message
      setStep('chat');
      setMessages([{
        id: 1,
        text: `Welcome Lahar! 🎓 Your profile saved.\nGPA: ${gpa} | Interests: ${interests}\n\nAsk me about colleges, admissions, fees!`,
        isAI: true
      }]);
      
    } catch (error) {
      alert('Error: ' + error.message);
    }
    setLoading(false);
  };

  const sendMessage = async () => {
    if (!inputMessage.trim()) return;

    // Add user message
    const userMsg = { id: Date.now(), text: inputMessage, isAI: false };
    setMessages(prev => [...prev, userMsg]);
    const messageToSend = inputMessage;
    setInputMessage('');
    setLoading(true);

    try {
      const response = await fetch('http://localhost:5000/api/chat', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          message: messageToSend,
          gpa: parseFloat(gpa),
          interests: interests
        })
      });

      const data = await response.json();
      
      // Add AI response
      setMessages(prev => [...prev, {
        id: Date.now() + 1,
        text: data.message,
        colleges: data.colleges,
        isAI: true
      }]);
      
    } catch (error) {
      setMessages(prev => [...prev, {
        id: Date.now() + 1,
        text: 'Sorry, AI is having trouble. Try again!',
        isAI: true
      }]);
    }
    setLoading(false);
  };

  if (step === 'profile') {
    return (
      <div className="profile-container">
        <div className="profile-form">
          <h1>🎓 AI College Counselor</h1>
          <p>Enter your profile for personalized recommendations</p>
          
          <input
            className="input-field"
            type="number"
            step="0.1"
            placeholder="GPA (e.g. 3.5)"
            value={gpa}
            onChange={(e) => setGpa(e.target.value)}
          />
          
          <input
            className="input-field"
            placeholder="Interests (CS, AI, Mechanical)"
            value={interests}
            onChange={(e) => setInterests(e.target.value)}
          />
          
          <button 
            className="submit-btn"
            onClick={submitProfile}
            disabled={loading}
          >
            {loading ? 'Saving...' : '🚀 Start AI Chat'}
          </button>
          
          <div className="status">
            Backend: <span className="green">localhost:5000 ✅</span>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="chat-container">
      <div className="chat-header">
        <h2>🤖 AI College Counselor</h2>
        <p>GPA: {gpa} | Interests: {interests}</p>
        <button className="back-btn" onClick={() => setStep('profile')}>
          ← Edit Profile
        </button>
      </div>
      
      <div className="messages">
        {messages.map((msg) => (
          <div key={msg.id} className={`message ${msg.isAI ? 'ai-message' : 'user-message'}`}>
            <div>{msg.text}</div>
            {msg.colleges && (
              <div className="college-list">
                {msg.colleges.map((college, idx) => (
                  <div key={idx} className="college-item">🏫 {college}</div>
                ))}
              </div>
            )}
          </div>
        ))}
        {loading && <div className="message ai-message">AI is typing...</div>}
        <div ref={messagesEndRef} />
      </div>
      
      <div className="chat-input">
        <input
          className="message-input"
          value={inputMessage}
          onChange={(e) => setInputMessage(e.target.value)}
          onKeyPress={(e) => e.key === 'Enter' && sendMessage()}
          placeholder="Ask about colleges, fees, admissions..."
          disabled={loading}
        />
        <button 
          className="send-btn" 
          onClick={sendMessage}
          disabled={loading || !inputMessage.trim()}
        >
          Send
        </button>
      </div>
    </div>
  );
}

export default App;
